input.command:
cat << 'PSEOF' > /tmp/process_st.ps1
$dir = "C:\Users\Administrator\Desktop\SHINJIN\1 CELL 조립 장비\PLC RAW\ST_XEC"
$files = @(
    "ST_01_MAIN", "ST_02_HMI", "ST_03_INPUT", "ST_04_OUTPUT", "ST_05_ALARM", "ST_06_SERVO",
    "ST_10_제품투입배출", "ST_11_플런저", "ST_12_스프링015", "ST_13_스프링023",
    "ST_14_댐퍼", "ST_15_구리스도포", "ST_16_코어", "ST_17_프레임",
    "ST_18_작동력검사", "ST_19_통전검사", "ST_20_불량배출"
)

$csvHeader = "변수 종류,이름,타입,메모리 할당,초기값,리테인,읽기 전용,EIP,OPC UA,HMI,축,디스크립션"

foreach ($f in $files) {
    $srcPath = Join-Path $dir "$f.st"
    $codePath = Join-Path $dir "${f}_code.st"
    $varPath = Join-Path $dir "${f}_var.csv"

    # Read file as UTF-8
    $lines = [System.IO.File]::ReadAllLines($srcPath, [System.Text.Encoding]::UTF8)

    # Find header comment block end, PROGRAM line, VAR/END_VAR positions
    $headerEnd = -1
    $programLine = -1
    $varStart = -1
    $varEnd = -1
    $endProgramLine = -1

    # Find header block: starts at line 0 with (* and ends before PROGRAM
    $inHeader = $false
    for ($i = 0; $i -lt $lines.Length; $i++) {
        $trimmed = $lines[$i].Trim()

        if ($i -eq 0 -and $trimmed.StartsWith("(*")) {
            $inHeader = $true
        }

        if ($inHeader) {
            if ($trimmed -match "\*\)\s*$" -and $i -gt 0) {
                # Check if next non-empty line is PROGRAM or another comment
                $nextNonEmpty = $i + 1
                while ($nextNonEmpty -lt $lines.Length -and $lines[$nextNonEmpty].Trim() -eq "") {
                    $nextNonEmpty++
                }
                if ($nextNonEmpty -lt $lines.Length) {
                    $nextTrimmed = $lines[$nextNonEmpty].Trim()
                    if ($nextTrimmed.StartsWith("PROGRAM") -or $nextTrimmed.StartsWith("(*")) {
                        # This might be end of header or a sub-comment
                        # Check: if the NEXT block after this closing *) is PROGRAM, this is header end
                        # Keep looking for PROGRAM
                    }
                }
                # Mark potential header end
                if ($headerEnd -eq -1) {
                    # First closing *) block
                }
            }
        }

        if ($trimmed -match "^PROGRAM\s+") {
            $programLine = $i
            # Header is everything before this PROGRAM line (skip empty lines between)
            $headerEnd = $i - 1
            while ($headerEnd -ge 0 -and $lines[$headerEnd].Trim() -eq "") {
                $headerEnd--
            }
            break
        }
    }

    # Now find VAR and END_VAR after PROGRAM line
    # Also handle case where there's no VAR block (like ST_02_HMI)
    for ($i = $programLine + 1; $i -lt $lines.Length; $i++) {
        $trimmed = $lines[$i].Trim()
        if ($trimmed -eq "VAR" -and $varStart -eq -1) {
            $varStart = $i
        }
        if ($trimmed -eq "END_VAR" -and $varStart -ne -1 -and $varEnd -eq -1) {
            $varEnd = $i
            break
        }
        # If we hit actual code (not comment, not empty, not VAR block), no VAR block
        if ($varStart -eq -1 -and $trimmed -ne "" -and -not $trimmed.StartsWith("(*") -and -not $trimmed.EndsWith("*)") -and -not $trimmed.StartsWith("VAR")) {
            # Check if this is a comment line
            if (-not ($trimmed.StartsWith("(*") -or $trimmed.Contains("(*"))) {
                break  # No VAR block
            }
        }
    }

    # Find END_PROGRAM
    for ($i = $lines.Length - 1; $i -ge 0; $i--) {
        if ($lines[$i].Trim() -eq "END_PROGRAM") {
            $endProgramLine = $i
            break
        }
    }

    # === Step A: Create _code.st ===
    # Code = everything after END_VAR (or after PROGRAM line if no VAR) until END_PROGRAM (inclusive)
    $codeLines = @()
    if ($varEnd -ne -1) {
        # Code starts after END_VAR
        $codeStart = $varEnd + 1
    } else {
        # No VAR block - code starts after PROGRAM line
        $codeStart = $programLine + 1
    }

    for ($i = $codeStart; $i -le $endProgramLine; $i++) {
        $codeLines += $lines[$i]
    }

    # Remove leading empty lines
    $codeText = ($codeLines -join "`n").TrimStart("`n", "`r")
    [System.IO.File]::WriteAllText($codePath, $codeText, [System.Text.Encoding]::UTF8)

    # === Step B: Create _var.csv ===
    $csvLines = @($csvHeader)

    if ($varStart -ne -1 -and $varEnd -ne -1) {
        for ($i = $varStart + 1; $i -lt $varEnd; $i++) {
            $line = $lines[$i].Trim()

            # Skip empty lines and comment-only lines
            if ($line -eq "" -or ($line.StartsWith("(*") -and $line.EndsWith("*)"))) {
                continue
            }

            # Parse variable declaration
            # Patterns:
            # name : TYPE;   (* comment *)
            # name : TYPE := INITIAL;   (* comment *)
            # name AT %addr : TYPE;   (* comment *)
            # name AT %addr : TYPE := INITIAL;

            # Extract comment first
            $comment = ""
            if ($line -match "\(\*\s*(.*?)\s*\*\)") {
                $comment = $Matches[1]
                $line = $line -replace "\(\*.*?\*\)", ""
                $line = $line.Trim()
            }

            # Remove trailing semicolon
            $line = $line.TrimEnd(";").Trim()

            if ($line -eq "" -or $line.StartsWith("(*")) { continue }

            # Parse: name [AT %addr] : TYPE [:= INITIAL]
            if ($line -match "^\s*(\S+)\s+AT\s+%\S+\s*:\s*(.+)$") {
                $varName = $Matches[1]
                $rest = $Matches[2].Trim()
            } elseif ($line -match "^\s*(\S+)\s*:\s*(.+)$") {
                $varName = $Matches[1]
                $rest = $Matches[2].Trim()
            } else {
                continue
            }

            # Parse rest: TYPE [:= INITIAL]
            $initial = ""
            $varType = ""
            if ($rest -match "^(\S+)\s*:=\s*(.+)$") {
                $varType = $Matches[1]
                $initial = $Matches[2].Trim()
            } else {
                $varType = $rest.Trim()
            }

            # Escape CSV fields
            $comment = $comment -replace '"', '""'
            if ($comment -match '[,"]') { $comment = '"' + $comment + '"' }

            $csvLines += "VAR,$varName,$varType,,$initial,0,0,0,0,0,0,$comment"
        }
    }

    # Write CSV in cp949
    $csvContent = $csvLines -join "`r`n"
    $cp949 = [System.Text.Encoding]::GetEncoding(949)
    $bytes = $cp949.GetBytes($csvContent)
    [System.IO.File]::WriteAllBytes($varPath, $bytes)

    # Report
    $varCount = $csvLines.Length - 1
    Write-Host "$f : code=$($codeLines.Length) lines, vars=$varCount"
}
Write-Host "`nDone! All 17 files processed."
PSEOF
powershell -ExecutionPolicy Bypass -File /tmp/process_st.ps1

powershell -NoProfile -ExecutionPolicy Bypass -Command '
$basePath = "C:/Users/Administrator/Desktop/SHINJIN/1 CELL 조립 장비/PLC RAW/ST_XEC"
$outPath = "$basePath/VAR_GLOBAL_ALL.csv"

# 결과 저장 배열
$rows = [System.Collections.ArrayList]::new()

# 파일별 영역 구분
$files = @{
    "GVL_INTERNAL.st" = "M"
    "GVL_DATA.st"     = "D"
    "GVL_TIMER.st"    = "T"
    "GVL_HMI.st"      = "K"
}

# 변수 선언 라인 파싱 정규식
# 패턴: name : type [AT %addr]; (* comment *)
$regex = "^\s+(\S+)\s*:\s*(BOOL|INT|DINT|TON|TOF|TP)\s*(?:AT\s+(%\S+))?\s*;\s*(?:\(\*\s*(.*?)\s*\*\))?\s*$"

$counts = @{ M=0; D=0; T=0; K=0 }

foreach ($file in $files.Keys) {
    $area = $files[$file]
    $filePath = "$basePath/$file"
    $content = [System.IO.File]::ReadAllText($filePath, [System.Text.Encoding]::UTF8)
    $lines = $content -split "`n"

    foreach ($line in $lines) {
        $line = $line.TrimEnd("`r")
        if ($line -match $regex) {
            $name = $Matches[1]
            $type = $Matches[2]
            $atAddr = if ($Matches[3]) { $Matches[3] } else { "" }
            $comment = if ($Matches[4]) { $Matches[4].Trim() } else { "" }

            # XG5000 유효성: 디바이스 접두사로 시작하는 이름에 언더스코어 추가
            # M/K/P/D/T/U + 숫자만으로 구성된 이름 -> 앞에 _ 추가
            if ($name -match "^[MKPDTU]\d+$") {
                $name = "_$name"
            }

            # 주소 매핑 (AT 없는 경우)
            $address = $atAddr
            if ([string]::IsNullOrEmpty($address)) {
                if ($area -eq "M") {
                    # _Mxxxxx 또는 _M0xxxx -> hex -> decimal -> %MXddd
                    if ($name -match "^_M([0-9A-Fa-f]+)$") {
                        $hexStr = $Matches[1]
                        $dec = [Convert]::ToInt32($hexStr, 16)
                        $address = "%MX$dec"
                    }
                }
                elseif ($area -eq "D") {
                    # _Dxxxxx -> decimal number -> %MWnnn
                    if ($name -match "^_D(\d+)$") {
                        $num = [int]$Matches[1]
                        $address = "%MW$num"
                    }
                }
                elseif ($area -eq "K") {
                    # _Kxxxxx -> hex -> decimal -> %KXddd
                    if ($name -match "^_K([0-9A-Fa-f]+)$") {
                        $hexStr = $Matches[1]
                        $dec = [Convert]::ToInt32($hexStr, 16)
                        $address = "%KX$dec"
                    }
                }
                elseif ($area -eq "T") {
                    # 타이머는 메모리 주소 없음
                    $address = ""
                }
            }

            # CSV 행 생성
            # 변수 종류,이름,타입,메모리 할당,초기값,리테인,읽기 전용,EIP,OPC UA,HMI,축,디스크립션
            $csvLine = "VAR_GLOBAL,$name,$type,$address,,0,0,0,0,0,0,$comment"
            [void]$rows.Add($csvLine)
            $counts[$area]++
        }
    }
}

# 헤더 + 내용
$header = "변수 종류,이름,타입,메모리 할당,초기값,리테인,읽기 전용,EIP,OPC UA,HMI,축,디스크립션"
$csvContent = $header + "`r`n" + ($rows -join "`r`n") + "`r`n"

# CP949 인코딩으로 저장
$bytes = [System.Text.Encoding]::GetEncoding(949).GetBytes($csvContent)
[System.IO.File]::WriteAllBytes($outPath, $bytes)

# 결과 출력
Write-Host "=== VAR_GLOBAL_ALL.csv 생성 완료 ==="
Write-Host "파일: $outPath"
Write-Host "M area: $($counts["M"])"
Write-Host "D area: $($counts["D"])"
Write-Host "T area: $($counts["T"])"
